import { GoogleGenAI, Type, FunctionDeclaration, GenerateContentResponse } from "@google/genai";
import { UserProfile } from "./types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const getBMICategoryFunction: FunctionDeclaration = {
  name: 'calculateBMI',
  parameters: {
    type: Type.OBJECT,
    description: 'Calculate BMI and provide medical category',
    properties: {
      weight: { type: Type.NUMBER, description: 'Weight in kg' },
      height: { type: Type.NUMBER, description: 'Height in cm' },
    },
    required: ['weight', 'height'],
  },
};

const findSpecialistFunction: FunctionDeclaration = {
  name: 'findSpecialist',
  parameters: {
    type: Type.OBJECT,
    description: 'Recommend a medical specialist type based on symptoms',
    properties: {
      symptoms: { type: Type.STRING, description: 'Description of symptoms' },
    },
    required: ['symptoms'],
  },
};

export const chatWithMediGenie = async (
  message: string,
  history: { role: 'user' | 'model'; parts: { text: string }[] }[],
  userProfile: UserProfile
) => {
  try {
    const systemInstruction = `
      You are MediGenie, a world-class AI medical assistant.
      Current User Context:
      - Name: ${userProfile.name}
      - Age: ${userProfile.age}
      - Medical History: ${userProfile.medicalHistory}
      - Allergies: ${userProfile.allergies.join(', ')}

      Guidelines:
      1. Always provide evidence-based medical information.
      2. Use Google Search grounding for the latest medical research or news.
      3. CRITICAL: Include a medical disclaimer that you are an AI and not a substitute for professional medical advice.
      4. If symptoms sound urgent (chest pain, severe bleeding, etc.), strongly advise seeking immediate emergency care.
      5. Be empathetic yet clinical and professional.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: [
        ...history,
        { role: 'user', parts: [{ text: message }] }
      ],
      config: {
        systemInstruction,
        tools: [
          { googleSearch: {} },
          { functionDeclarations: [getBMICategoryFunction, findSpecialistFunction] }
        ],
      },
    });

    return response;
  } catch (error) {
    console.error("Gemini Error:", error);
    throw error;
  }
};

import React, { useState, useEffect } from 'react';
import { HashRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import Header from './components/Header';
import Sidebar from './components/Sidebar';
import Dashboard from './pages/Dashboard';
import Chat from './pages/Chat';
import Onboarding from './pages/Onboarding';
import Profile from './pages/Profile';
import Tools from './pages/Tools';
import { UserProfile } from './types';

const INITIAL_PROFILE: UserProfile = {
  name: '',
  age: 0,
  gender: 'Other',
  weight: 0,
  height: 0,
  bloodGroup: 'Unknown',
  allergies: [],
  medicalHistory: '',
  isRegistered: false,
};

const App: React.FC = () => {
  const [userProfile, setUserProfile] = useState<UserProfile>(() => {
    const saved = localStorage.getItem('medi_profile');
    return saved ? JSON.parse(saved) : INITIAL_PROFILE;
  });

  useEffect(() => {
    localStorage.setItem('medi_profile', JSON.stringify(userProfile));
  }, [userProfile]);

  const handleRegister = (profile: UserProfile) => {
    setUserProfile({ ...profile, isRegistered: true });
  };

  if (!userProfile.isRegistered) {
    return <Onboarding onComplete={handleRegister} />;
  }

  return (
    <Router>
      <div className="flex h-screen bg-slate-50 overflow-hidden">
        <Sidebar />
        <div className="flex-1 flex flex-col min-w-0 overflow-hidden">
          <Header profile={userProfile} />
          <main className="flex-1 overflow-y-auto p-4 md:p-8">
            <Routes>
              <Route path="/" element={<Dashboard profile={userProfile} />} />
              <Route path="/chat" element={<Chat profile={userProfile} />} />
              <Route path="/tools" element={<Tools profile={userProfile} />} />
              <Route path="/profile" element={<Profile profile={userProfile} setProfile={setUserProfile} />} />
              <Route path="*" element={<Navigate to="/" />} />
            </Routes>
          </main>
        </div>
      </div>
    </Router>
  );
};

export default App;

