import React, { useState, useRef, useEffect } from 'react';
import { UserProfile, ChatMessage } from '../types';
import { chatWithMediGenie } from '../geminiService';
import { Send, User, ShieldCheck, Info, Loader2, Search, ExternalLink } from 'lucide-react';

const Chat: React.FC<{ profile: UserProfile }> = ({ profile }) => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    {
      role: 'model',
      text: `Hello ${profile.name}, I'm MediGenie. I've reviewed your medical profile (Age: ${profile.age}, Allergies: ${profile.allergies.join(', ') || 'None'}). How can I assist with your health today?`,
      timestamp: new Date()
    }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isTyping]);

  const handleSend = async () => {
    if (!input.trim() || isTyping) return;

    const userMsg: ChatMessage = { role: 'user', text: input, timestamp: new Date() };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsTyping(true);

    try {
      const history = messages.map(m => ({
        role: m.role,
        parts: [{ text: m.text }]
      }));

      const response = await chatWithMediGenie(input, history, profile);
      const text = response.text || "I'm sorry, I couldn't generate a response.";

      const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
      const sources = groundingChunks
        .filter((c: any) => c.web)
        .map((c: any) => ({ title: c.web.title, uri: c.web.uri }));

      const botMsg: ChatMessage = {
        role: 'model',
        text,
        timestamp: new Date(),
        sources: sources.length > 0 ? sources : undefined
      };
      setMessages(prev => [...prev, botMsg]);
    } catch (error) {
      setMessages(prev => [...prev, {
        role: 'model',
        text: "I encountered an error. Please try again later.",
        timestamp: new Date()
      }]);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <div className="flex flex-col h-full max-w-4xl mx-auto border glass rounded-3xl overflow-hidden shadow-xl">
      <div className="bg-blue-600 p-4 text-white flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-white/20 rounded-full flex items-center justify-center">
            <ShieldCheck className="w-6 h-6" />
          </div>
          <div>
            <h3 className="font-bold">MediGenie AI</h3>
            <p className="text-xs text-blue-100 flex items-center gap-1">
              <span className="w-1.5 h-1.5 bg-green-400 rounded-full animate-pulse"></span>
              Secure Medical Assistant
            </p>
          </div>
        </div>
        <div className="hidden sm:flex items-center gap-2 bg-white/10 px-3 py-1.5 rounded-lg text-xs">
          <Info size={14} />
          <span>Not for emergencies</span>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-6 space-y-6 bg-slate-50/50" ref={scrollRef}>
        {messages.map((m, i) => (
          <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`flex gap-3 max-w-[85%] ${m.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
              <div className={`w-8 h-8 rounded-full flex items-center justify-center shrink-0 ${m.role === 'user' ? 'bg-blue-600' : 'bg-slate-200'}`}>
                {m.role === 'user' ? <User size={16} className="text-white" /> : <ShieldCheck size={16} className="text-blue-600" />}
              </div>
              <div className="space-y-2">
                <div className={`p-4 rounded-2xl shadow-sm ${
                  m.role === 'user' 
                  ? 'bg-blue-600 text-white rounded-tr-none' 
                  : 'bg-white text-slate-800 rounded-tl-none border border-slate-100'
                }`}>
                  <p className="text-sm leading-relaxed whitespace-pre-wrap">{m.text}</p>
                </div>
                {m.sources && m.sources.length > 0 && (
                  <div className="bg-white/50 p-3 rounded-xl border border-slate-100 space-y-2">
                    <p className="text-[10px] font-bold text-slate-400 uppercase flex items-center gap-1">
                      <Search size={10} /> Sources Used
                    </p>
                    {m.sources.map((s, idx) => (
                      <a 
                        key={idx} 
                        href={s.uri} 
                        target="_blank" 
                        rel="noopener noreferrer"
                        className="flex items-center justify-between text-xs text-blue-600 hover:underline bg-white p-2 rounded-lg border border-slate-100 group"
                      >
                        <span className="truncate pr-4">{s.title}</span>
                        <ExternalLink size={12} className="shrink-0 opacity-0 group-hover:opacity-100 transition-opacity" />
                      </a>
                    ))}
                  </div>
                )}
                <p className={`text-[10px] text-slate-400 ${m.role === 'user' ? 'text-right' : 'text-left'}`}>
                  {m.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                </p>
              </div>
            </div>
          </div>
        ))}
        {isTyping && (
          <div className="flex justify-start">
            <div className="flex gap-3 items-center">
              <div className="w-8 h-8 rounded-full bg-slate-200 flex items-center justify-center">
                <ShieldCheck size={16} className="text-blue-600" />
              </div>
              <div className="bg-white p-4 rounded-2xl rounded-tl-none shadow-sm border border-slate-100">
                <Loader2 className="w-5 h-5 animate-spin text-blue-600" />
              </div>
            </div>
          </div>
        )}
      </div>

      <div className="p-4 bg-white border-t">
        <div className="flex items-center gap-2 max-w-4xl mx-auto">
          <input
            type="text"
            className="flex-1 bg-slate-100 rounded-2xl px-6 py-3 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500/20 transition-all"
            placeholder="Ask about symptoms, medications, or health tips..."
            value={input}
            onChange={e => setInput(e.target.value)}
            onKeyDown={e => e.key === 'Enter' && handleSend()}
          />
          <button
            onClick={handleSend}
            disabled={isTyping}
            className="w-12 h-12 bg-blue-600 hover:bg-blue-700 disabled:bg-slate-300 text-white rounded-2xl flex items-center justify-center transition-all shadow-lg shadow-blue-200"
          >
            <Send size={20} />
          </button>
        </div>
        <p className="text-[10px] text-slate-400 text-center mt-2">
          MediGenie AI provides informational support and is not for diagnosis or emergencies. 
        </p>
      </div>
    </div>
  );
};

export default Chat;

import React, { useState } from 'react';
import { UserProfile } from '../types';
import { Save, User, Scale, Ruler, Droplet, AlertTriangle } from 'lucide-react';

interface ProfileProps {
  profile: UserProfile;
  setProfile: (profile: UserProfile) => void;
}

const Profile: React.FC<ProfileProps> = ({ profile, setProfile }) => {
  const [editedProfile, setEditedProfile] = useState<UserProfile>(profile);
  const [showSaved, setShowSaved] = useState(false);

  const handleSave = () => {
    setProfile(editedProfile);
    setShowSaved(true);
    setTimeout(() => setShowSaved(false), 3000);
  };

  return (
    <div className="max-w-4xl mx-auto space-y-8">
      <div className="flex items-center justify-between">
        <h2 className="text-3xl font-bold text-slate-900">My Health Profile</h2>
        <button 
          onClick={handleSave}
          className="bg-blue-600 text-white px-6 py-2.5 rounded-xl font-semibold flex items-center gap-2 hover:bg-blue-700 transition-all shadow-lg shadow-blue-100"
        >
          <Save size={18} /> Save Profile
        </button>
      </div>

      {showSaved && (
        <div className="bg-emerald-100 border border-emerald-200 text-emerald-700 px-4 py-3 rounded-xl animate-in fade-in slide-in-from-top-4">
          Profile updated successfully!
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
        <div className="md:col-span-1 space-y-6">
          <div className="bg-white p-8 rounded-3xl border border-slate-100 shadow-sm text-center">
            <div className="w-24 h-24 bg-blue-100 rounded-full mx-auto flex items-center justify-center mb-4">
              <User size={48} className="text-blue-600" />
            </div>
            <h3 className="text-xl font-bold text-slate-900">{profile.name}</h3>
            <p className="text-slate-500 text-sm">{profile.gender}, {profile.age} years old</p>
          </div>

          <div className="bg-amber-50 p-6 rounded-3xl border border-amber-100 space-y-4">
            <div className="flex items-center gap-2 text-amber-700 font-bold">
              <AlertTriangle size={18} />
              <h4>Allergies & Alerts</h4>
            </div>
            <div className="flex flex-wrap gap-2">
              {editedProfile.allergies.map((a, i) => (
                <span key={i} className="bg-white px-3 py-1 rounded-full text-xs font-semibold text-amber-800 border border-amber-200">
                  {a}
                </span>
              ))}
              {editedProfile.allergies.length === 0 && <p className="text-xs text-amber-600 italic">No allergies listed.</p>}
            </div>
          </div>
        </div>

        <div className="md:col-span-2 space-y-6">
          <div className="bg-white p-8 rounded-3xl border border-slate-100 shadow-sm space-y-6">
            <h4 className="font-bold text-lg text-slate-900 border-b pb-4">Biometric Data</h4>
            <div className="grid grid-cols-2 gap-6">
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-500 flex items-center gap-2">
                  <Scale size={16} /> Weight (kg)
                </label>
                <input 
                  type="number" 
                  className="w-full bg-slate-50 border border-slate-100 rounded-xl px-4 py-2 focus:ring-2 focus:ring-blue-500 outline-none"
                  value={editedProfile.weight}
                  onChange={e => setEditedProfile({...editedProfile, weight: parseFloat(e.target.value)})}
                />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-500 flex items-center gap-2">
                  <Ruler size={16} /> Height (cm)
                </label>
                <input 
                  type="number" 
                  className="w-full bg-slate-50 border border-slate-100 rounded-xl px-4 py-2 focus:ring-2 focus:ring-blue-500 outline-none"
                  value={editedProfile.height}
                  onChange={e => setEditedProfile({...editedProfile, height: parseFloat(e.target.value)})}
                />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium text-slate-500 flex items-center gap-2">
                  <Droplet size={16} /> Blood Group
                </label>
                <select 
                  className="w-full bg-slate-50 border border-slate-100 rounded-xl px-4 py-2 outline-none"
                  value={editedProfile.bloodGroup}
                  onChange={e => setEditedProfile({...editedProfile, bloodGroup: e.target.value})}
                >
                  {['A+', 'A-', 'B+', 'B-', 'AB+', 'AB-', 'O+', 'O-'].map(g => <option key={g}>{g}</option>)}
                </select>
              </div>
            </div>
          </div>

          <div className="bg-white p-8 rounded-3xl border border-slate-100 shadow-sm space-y-4">
            <h4 className="font-bold text-lg text-slate-900 border-b pb-4">Medical Background</h4>
            <textarea 
              className="w-full bg-slate-50 border border-slate-100 rounded-xl px-4 py-3 h-40 outline-none focus:ring-2 focus:ring-blue-500"
              value={editedProfile.medicalHistory}
              onChange={e => setEditedProfile({...editedProfile, medicalHistory: e.target.value})}
              placeholder="List any chronic conditions, past surgeries, or long-term medications..."
            />
          </div>
        </div>
      </div>
    </div>
  );
