import { GoogleGenAI, Type, FunctionDeclaration } from "@google/genai";
import { UserProfile, TriageStep, CarePathway } from "./types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getNextTriageStep = async (
  userProfile: UserProfile,
  currentSymptoms: string,
  history: { question: string; answer: string }[]
): Promise<TriageStep> => {
  const systemInstruction = `
    You are an Expert Medical Triage Agent. 
    Your goal is to conduct a multi-step structured interview to assess a patient's risk.

    Current User Profile:
    - Name: ${userProfile.name}
    - Age: ${userProfile.age}
    - Gender: ${userProfile.gender}
    - Medical History: ${userProfile.medicalHistory}
    - Allergies: ${userProfile.allergies.join(', ')}

    Rules:
    1. Ask ONE highly relevant question at a time to narrow down the diagnosis.
    2. If symptoms sound life-threatening (chest pain, stroke signs, severe bleeding), set riskLevel to 'Emergency' and isComplete to true immediately.
    3. If you have enough information (usually after 3-5 questions), set isComplete to true and provide a TriageResult.
    4. Provide 2-4 possible multiple-choice options for the user to make it easier.

    Response MUST be valid JSON matching the TriageStep interface.
  `;

  const prompt = `
    Symptoms described so far: ${currentSymptoms}
    Interview history: ${JSON.stringify(history)}
    What is the next question or final result?
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: [{ role: 'user', parts: [{ text: prompt }] }],
    config: {
      systemInstruction,
      responseMimeType: "application/json",
    },
  });

  return JSON.parse(response.text || '{}');
};

export const generateCarePathway = async (
  userProfile: UserProfile,
  symptoms: string,
  lifestyle: { sleep: string; diet: string; stress: string }
): Promise<CarePathway> => {
  const systemInstruction = `
    You are a Personalized Care Pathway Generator.
    Create a comprehensive roadmap for a user's recovery or management based on their profile, symptoms, and lifestyle.

    User: ${userProfile.name} (${userProfile.age}y, ${userProfile.gender})
    Medical History: ${userProfile.medicalHistory}
    Lifestyle: Sleep: ${lifestyle.sleep}, Diet: ${lifestyle.diet}, Stress: ${lifestyle.stress}

    Response MUST be valid JSON matching the CarePathway interface.
    Ensure "redFlags" are specific and high-priority.
  `;

  const prompt = `Generate a care pathway for symptoms: ${symptoms}`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: [{ role: 'user', parts: [{ text: prompt }] }],
    config: {
      systemInstruction,
      responseMimeType: "application/json",
    },
  });

  return JSON.parse(response.text || '{}');
};

export const chatWithMediGenie = async (
  message: string,
  history: { role: 'user' | 'model'; parts: { text: string }[] }[],
  userProfile: UserProfile
) => {
  try {
    const systemInstruction = `
      You are MediGenie, a world-class AI medical assistant.
      Current User Context:
      - Name: ${userProfile.name}
      - Age: ${userProfile.age}
      - Medical History: ${userProfile.medicalHistory}
      - Allergies: ${userProfile.allergies.join(', ')}

      Guidelines:
      1. Always provide evidence-based medical information.
      2. Use Google Search grounding for the latest medical research or news.
      3. CRITICAL: Include a medical disclaimer.
      4. If symptoms sound urgent, strongly advise seeking immediate emergency care.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: [
        ...history,
        { role: 'user', parts: [{ text: message }] }
      ],
      config: {
        systemInstruction,
        tools: [{ googleSearch: {} }],
      },
    });

    return response;
  } catch (error) {
    console.error("Gemini Error:", error);
    throw error;
  }
};

