              value={specialty}
              onChange={(e) => setSpecialty(e.target.value)}
            >
              {['General', 'Emergency', 'Dental', 'Pediatrics', 'Cardiology', 'Mental Health', 'Radiology'].map(s => (
                <option key={s}>{s}</option>
              ))}
