import { GoogleGenAI, Type, FunctionDeclaration } from "@google/genai";
import { UserProfile, TriageStep, CarePathway } from "./types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const checkDrugInteractions = async (medications: string[]) => {
  const systemInstruction = `
    You are a clinical pharmacologist. Analyze the following list of medications for potential drug-drug interactions.
    Identify severity (Major, Moderate, Minor) and provide a concise explanation.
    Always include a disclaimer that this is for informational purposes only.
  `;
  const prompt = `Check interactions for: ${medications.join(', ')}`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: [{ role: 'user', parts: [{ text: prompt }] }],
    config: { systemInstruction },
  });
  return response.text;
};

export const findNearbyClinics = async (specialty: string, lat: number, lng: number) => {
  const prompt = `Find ${specialty} clinics near my location.`;

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash',
    contents: [{ role: 'user', parts: [{ text: prompt }] }],
    config: {
      tools: [{ googleMaps: {} }],
      toolConfig: {
        retrievalConfig: {
          latLng: { latitude: lat, longitude: lng }
        }
      }
    },
  });
  return response;
};

export const parseLabReport = async (content: string | { data: string, mimeType: string }) => {
  const systemInstruction = `
    You are a medical lab specialist. Explain the following lab results in simple, non-medical terms.
    Focus on:
    1. What the test measures.
    2. If any values are outside normal ranges (high/low).
    3. Suggested questions for a doctor.
  `;

  const parts = typeof content === 'string' 
    ? [{ text: content }] 
    : [{ inlineData: content }, { text: "Please analyze this lab report image." }];

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: [{ role: 'user', parts }],
    config: { systemInstruction },
  });
  return response.text;
};

export const searchMedicalInfo = async (query: string) => {
  const systemInstruction = `
    You are a medical research assistant. Provide an up-to-date summary for the user's query based on latest research.
    Always use Google Search grounding and cite your sources.
  `;

  const response = await ai.models.generateContent({
