export const chatWithMediGenie = async (
  message: string,
  imageData: string | null,
  history: any[],
  userProfile: UserProfile
) => {
  const systemInstruction = `
    You are MediGenie, a professional and empathetic AI medical assistant.
    User Profile: ${userProfile.name}, ${userProfile.age}y, Allergies: ${userProfile.allergies.join(', ')}.

    GUIDELINES:
    1. Assess confidence based on input modality:
       - Text only: High confidence for general info, Medium for specific symptoms.
       - Text + Image (rashes, reports): Medium confidence, explicitly state "This analysis is based on visual interpretation and is not a clinical diagnosis."
       - Text + Voice: High confidence.
    2. Always end responses with a clear confidence level indicator (Low/Medium/High) and a brief reason.
    3. NEVER provide a final diagnosis. Always suggest relevant medical specialists.
    4. Use Google Search grounding for up-to-date clinical information.
    5. If an image of a rash or wound is provided, ask about duration, pain, and itching to improve interpretation.
  `;

  const userParts: any[] = [{ text: message }];
  if (imageData) {
    userParts.push({
      inlineData: {
        data: imageData.split(',')[1],
        mimeType: 'image/jpeg'
      }
    });
  }

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: [
      ...history,
      { role: 'user', parts: userParts }
    ],
    config: { 
      systemInstruction,
      tools: [{ googleSearch: {} }] 
    },
  });

  return response;
};

import React, { useState, useRef, useEffect } from 'react';
import { UserProfile, ChatMessage } from '../types';
import { chatWithMediGenie } from '../geminiService';
import { 
  Send, User, ShieldCheck, Info, Loader2, Search, 
  ExternalLink, Mic, MicOff, Image as ImageIcon, X, AlertCircle 
} from 'lucide-react';

const Chat: React.FC<{ profile: UserProfile }> = ({ profile }) => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    {
      role: 'model',
      text: `Hello ${profile.name}, I'm MediGenie. I can now analyze photos of rashes or lab reports, and you can also talk to me by clicking the microphone. How can I assist you today?`,
      timestamp: new Date()
    }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [selectedImage, setSelectedImage] = useState<string | null>(null);
  const scrollRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const recognitionRef = useRef<any>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isTyping]);

  // Speech Recognition Setup
  useEffect(() => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (SpeechRecognition) {
      recognitionRef.current = new SpeechRecognition();
      recognitionRef.current.continuous = false;
      recognitionRef.current.interimResults = false;
      recognitionRef.current.lang = 'en-US';

      recognitionRef.current.onresult = (event: any) => {
        const transcript = event.results[0][0].transcript;
        setInput(prev => prev + (prev ? ' ' : '') + transcript);
        setIsListening(false);
      };

      recognitionRef.current.onerror = () => setIsListening(false);
      recognitionRef.current.onend = () => setIsListening(false);
    }
  }, []);

  const toggleListening = () => {
    if (isListening) {
      recognitionRef.current?.stop();
    } else {
      setIsListening(true);
      recognitionRef.current?.start();
    }
  };

  const handleImageSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setSelectedImage(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handleSend = async () => {
    if ((!input.trim() && !selectedImage) || isTyping) return;

    const userMsg: ChatMessage = { 
      role: 'user', 
      text: input || (selectedImage ? "Please analyze this image." : ""), 
      image: selectedImage || undefined,
      timestamp: new Date() 
    };

    setMessages(prev => [...prev, userMsg]);
    const currentInput = input;
    const currentImage = selectedImage;

    setInput('');
    setSelectedImage(null);
    setIsTyping(true);

    try {
      const history = messages.map(m => ({
        role: m.role,
        parts: [{ text: m.text }]
      }));

      const response = await chatWithMediGenie(currentInput || "Analyze image.", currentImage, history, profile);
      const fullText = response.text || "I'm sorry, I couldn't generate a response.";

      // Extract confidence from bottom of text if present (simple heuristic)
      let confidence: 'Low' | 'Medium' | 'High' | undefined;
      if (fullText.toLowerCase().includes('confidence: high')) confidence = 'High';
      else if (fullText.toLowerCase().includes('confidence: medium')) confidence = 'Medium';
      else if (fullText.toLowerCase().includes('confidence: low')) confidence = 'Low';

      const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
      const sources = groundingChunks
        .filter((c: any) => c.web)
        .map((c: any) => ({ title: c.web.title, uri: c.web.uri }));

      const botMsg: ChatMessage = {
        role: 'model',
        text: fullText,
        timestamp: new Date(),
        sources: sources.length > 0 ? sources : undefined,
        confidence
      };
      setMessages(prev => [...prev, botMsg]);
    } catch (error) {
      setMessages(prev => [...prev, {
        role: 'model',
        text: "I encountered an error analyzing your request. Please try again.",
        timestamp: new Date()
      }]);
    } finally {
      setIsTyping(false);
    }
  };

  const getConfidenceColor = (level?: string) => {
    switch(level) {
      case 'High': return 'text-emerald-500 bg-emerald-50 border-emerald-100';
      case 'Medium': return 'text-amber-500 bg-amber-50 border-amber-100';
      case 'Low': return 'text-rose-500 bg-rose-50 border-rose-100';
      default: return 'text-slate-400 bg-slate-50 border-slate-100';
    }
  };

  return (
    <div className="flex flex-col h-full max-w-4xl mx-auto border glass rounded-3xl overflow-hidden shadow-xl">
      <div className="bg-blue-600 p-4 text-white flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-white/20 rounded-full flex items-center justify-center">
            <ShieldCheck className="w-6 h-6" />
          </div>
          <div>
            <h3 className="font-bold">MediGenie AI</h3>
            <p className="text-xs text-blue-100 flex items-center gap-1">
              <span className="w-1.5 h-1.5 bg-green-400 rounded-full animate-pulse"></span>
              Multi-Modal Analysis Active
            </p>
          </div>
        </div>
        <div className="hidden sm:flex items-center gap-2 bg-white/10 px-3 py-1.5 rounded-lg text-xs">
          <Info size={14} />
          <span>Not for emergencies</span>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-6 space-y-6 bg-slate-50/50" ref={scrollRef}>
        {messages.map((m, i) => (
          <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`flex gap-3 max-w-[85%] ${m.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
              <div className={`w-8 h-8 rounded-full flex items-center justify-center shrink-0 ${m.role === 'user' ? 'bg-blue-600' : 'bg-slate-200'}`}>
                {m.role === 'user' ? <User size={16} className="text-white" /> : <ShieldCheck size={16} className="text-blue-600" />}
              </div>
              <div className="space-y-2">
                <div className={`p-4 rounded-2xl shadow-sm space-y-3 ${
                  m.role === 'user' 
                  ? 'bg-blue-600 text-white rounded-tr-none' 
                  : 'bg-white text-slate-800 rounded-tl-none border border-slate-100'
                }`}>
                  {m.image && (
                    <div className="rounded-xl overflow-hidden mb-2 max-w-[240px]">
                      <img src={m.image} alt="Upload" className="w-full h-auto object-cover" />
                    </div>
                  )}
                  <p className="text-sm leading-relaxed whitespace-pre-wrap">{m.text}</p>
                </div>

                {m.confidence && (
                  <div className={`inline-flex items-center gap-1.5 px-3 py-1 rounded-full text-[10px] font-bold border uppercase tracking-wider ${getConfidenceColor(m.confidence)}`}>
                    <AlertCircle size={10} /> Confidence: {m.confidence}
                  </div>
                )}

                {m.sources && m.sources.length > 0 && (
                  <div className="bg-white/50 p-3 rounded-xl border border-slate-100 space-y-2">
                    <p className="text-[10px] font-bold text-slate-400 uppercase flex items-center gap-1">
                      <Search size={10} /> Research Grounding
                    </p>
                    {m.sources.map((s, idx) => (
                      <a 
                        key={idx} 
                        href={s.uri} 
                        target="_blank" 
                        rel="noopener noreferrer"
                        className="flex items-center justify-between text-xs text-blue-600 hover:underline bg-white p-2 rounded-lg border border-slate-100 group"
                      >
                        <span className="truncate pr-4">{s.title}</span>
                        <ExternalLink size={12} className="shrink-0 opacity-0 group-hover:opacity-100 transition-opacity" />
                      </a>
                    ))}
                  </div>
                )}
                <p className={`text-[10px] text-slate-400 ${m.role === 'user' ? 'text-right' : 'text-left'}`}>
                  {m.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                </p>
              </div>
            </div>
          </div>
        ))}
        {isTyping && (
          <div className="flex justify-start">
            <div className="flex gap-3 items-center">
              <div className="w-8 h-8 rounded-full bg-slate-200 flex items-center justify-center">
                <ShieldCheck size={16} className="text-blue-600" />
              </div>
              <div className="bg-white p-4 rounded-2xl rounded-tl-none shadow-sm border border-slate-100">
                <Loader2 className="w-5 h-5 animate-spin text-blue-600" />
              </div>
            </div>
          </div>
        )}
      </div>

      <div className="p-4 bg-white border-t">
        {selectedImage && (
          <div className="mb-4 flex items-center gap-3 bg-slate-50 p-2 rounded-2xl border border-dashed border-slate-200 animate-in slide-in-from-bottom-2">
            <div className="w-16 h-16 rounded-xl overflow-hidden relative">
              <img src={selectedImage} alt="Preview" className="w-full h-full object-cover" />
              <button 
                onClick={() => setSelectedImage(null)}
                className="absolute top-1 right-1 bg-black/50 text-white rounded-full p-1 hover:bg-black/70"
              >
                <X size={10} />
              </button>
            </div>
            <div className="text-xs text-slate-500">
              <p className="font-bold">Image Attached</p>
              <p>Analysing modality: Visual</p>
            </div>
          </div>
        )}

        <div className="flex items-center gap-2 max-w-4xl mx-auto">
          <input 
            type="file" 
            ref={fileInputRef} 
            className="hidden" 
            accept="image/*" 
            onChange={handleImageSelect}
          />
          <button
            onClick={() => fileInputRef.current?.click()}
            className="w-10 h-10 bg-slate-100 text-slate-500 hover:bg-slate-200 hover:text-blue-600 rounded-xl flex items-center justify-center transition-all shrink-0"
            title="Attach Image"
          >
            <ImageIcon size={20} />
          </button>

          <button
            onClick={toggleListening}
            className={`w-10 h-10 rounded-xl flex items-center justify-center transition-all shrink-0 ${isListening ? 'bg-rose-500 text-white animate-pulse shadow-lg shadow-rose-200' : 'bg-slate-100 text-slate-500 hover:bg-slate-200 hover:text-rose-500'}`}
            title="Voice Input"
          >
            {isListening ? <MicOff size={20} /> : <Mic size={20} />}
          </button>

          <input
            type="text"
            className="flex-1 bg-slate-100 rounded-2xl px-6 py-3 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500/20 transition-all"
            placeholder={isListening ? "Listening..." : "Ask about symptoms, attach a photo..."}
            value={input}
            onChange={e => setInput(e.target.value)}
            onKeyDown={e => e.key === 'Enter' && handleSend()}
          />

          <button
            onClick={handleSend}
            disabled={isTyping || (!input.trim() && !selectedImage)}
            className="w-12 h-12 bg-blue-600 hover:bg-blue-700 disabled:bg-slate-300 text-white rounded-2xl flex items-center justify-center transition-all shadow-lg shadow-blue-200 shrink-0"
          >
            <Send size={20} />
          </button>
        </div>
        <p className="text-[10px] text-slate-400 text-center mt-2 flex items-center justify-center gap-1">
          <AlertCircle size={10} /> MediGenie provides informational analysis. Never ignore professional medical advice.
        </p>
      </div>
    </div>
  );
};

