import { GoogleGenAI, Type } from "@google/genai";
import { UserProfile, TriageStep, CarePathway, AgentName } from "./types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

/**
 * Multi-Agent Orchestrator
 * Each function below acts as a specialized Agent with strict system instructions.
 */

// 1. Safety & Compliance Agent (Global boundary enforcer)
const SAFETY_INSTRUCTIONS = `
  STRICT SAFETY RULES:
  - NEVER state a definitive diagnosis.
  - ALWAYS include: "This is not medical advice. Consult a doctor."
  - If "Emergency" risk is detected, stop all other logic and insist on calling emergency services.
`;

// 2. Symptom Analysis Agent
export const analyzeSymptomsAgent = async (input: string, imageData?: string) => {
  const systemInstruction = `
    You are the Symptom Analysis Agent. 
    Task: Interpret text, voice transcripts, or images (rashes, reports).
    Output: Describe clinical observations but avoid diagnosis.
    ${SAFETY_INSTRUCTIONS}
  `;
  const parts: any[] = [{ text: input }];
  if (imageData) parts.push({ inlineData: { data: imageData.split(',')[1], mimeType: 'image/jpeg' } });

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: [{ role: 'user', parts }],
    config: { systemInstruction },
  });
  return response.text;
};

// 3. Medical Knowledge Agent (Librarian)
export const queryKnowledgeAgent = async (query: string) => {
  const systemInstruction = `
    You are the Medical Knowledge Agent. 
    Task: Find latest clinical guidelines, research papers, and drug data using Google Search.
    Output: Evidence-based summaries with source links.
    ${SAFETY_INSTRUCTIONS}
  `;
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: [{ role: 'user', parts: [{ text: query }] }],
    config: { 
      systemInstruction,
      tools: [{ googleSearch: {} }] 
    },
  });
  return response;
};

// 4. Risk Assessment Agent
export const evaluateRiskAgent = async (history: any[], currentData: any) => {
  const systemInstruction = `
    You are the Risk Evaluator Agent.
    Task: Score health risk from 0-100 and set urgency (Low/Medium/High/Emergency).
    Output: A risk profile based on clinical indicators.
    ${SAFETY_INSTRUCTIONS}
  `;
  // Internal logic call...
};

// 5. Action Planner Agent (Coordinator for Triage & Pathways)
export const planActionAgent = async (userProfile: UserProfile, symptoms: string): Promise<CarePathway> => {
  const systemInstruction = `
    You are the Action Planner Agent.
    Task: Decide next clinical steps. Should the user see a doctor? What tests are likely?
    Response: Valid JSON matching CarePathway interface.
    ${SAFETY_INSTRUCTIONS}
  `;
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: [{ role: 'user', parts: [{ text: `Symptoms: ${symptoms}. Profile: ${JSON.stringify(userProfile)}` }] }],
    config: { systemInstruction, responseMimeType: "application/json" },
  });
  return JSON.parse(response.text || '{}');
};

// 6. Follow-up Agent
export const followUpAgent = async (previousLogs: any[], currentUpdate: string) => {
  const systemInstruction = `
    You are the Follow-up Coordinator.
    Task: Compare current status with previous logs. Is the condition improving or worsening?
    Output: Encouragement or a warning to seek care if worsening.
    ${SAFETY_INSTRUCTIONS}
  `;
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: [{ role: 'user', parts: [{ text: `Update: ${currentUpdate}. History: ${JSON.stringify(previousLogs)}` }] }],
    config: { systemInstruction },
  });
  return response.text;
};

// Main Chat Orchestrator
export const chatWithMediGenie = async (
  message: string,
  imageData: string | null,
  history: any[],
  userProfile: UserProfile
) => {
  const systemInstruction = `
    You are the MediGenie Orchestrator. 
    Coordinate between:
    - Symptom Analyzer (for image/symptom input)
    - Medical Librarian (for research/grounding)
    - Risk Evaluator (for confidence and safety)
    - Action Planner (for next steps)

    Structure your response to show which agent is handling which part of the answer.
    Confidence Scoring: Low/Medium/High based on modality.
    ${SAFETY_INSTRUCTIONS}
  `;

  const userParts: any[] = [{ text: message }];
  if (imageData) {
    userParts.push({ inlineData: { data: imageData.split(',')[1], mimeType: 'image/jpeg' } });
  }

  return await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: [...history, { role: 'user', parts: userParts }],
    config: { 
      systemInstruction,
      tools: [{ googleSearch: {} }] 
    },
  });
};

