  ExternalLink, Mic, MicOff, Image as ImageIcon, X, AlertCircle,
  BrainCircuit, Library, ShieldAlert, ClipboardCheck, Lock
} from 'lucide-react';

const AgentBadge = ({ name }: { name: AgentName }) => {
