      {getIcon()} {name}
    </span>
  );
};

const Chat: React.FC<{ profile: UserProfile }> = ({ profile }) => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    {
      role: 'model',
      text: `Hello ${profile.name}, I'm MediGenie Orchestrator. I've coordinated my specialized agents to assist you with symptom analysis, research, and safety checks.`,
      timestamp: new Date(),
      activeAgent: 'Safety Officer'
    }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [selectedImage, setSelectedImage] = useState<string | null>(null);
  const scrollRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const recognitionRef = useRef<any>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isTyping]);

  useEffect(() => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (SpeechRecognition) {
      recognitionRef.current = new SpeechRecognition();
      recognitionRef.current.onresult = (e: any) => {
        setInput(prev => prev + ' ' + e.results[0][0].transcript);
        setIsListening(false);
      };
      recognitionRef.current.onend = () => setIsListening(false);
    }
  }, []);

  const handleSend = async () => {
    if ((!input.trim() && !selectedImage) || isTyping) return;

    const userMsg: ChatMessage = { 
      role: 'user', 
      text: input || (selectedImage ? "Please analyze this image." : ""), 
      image: selectedImage || undefined,
      timestamp: new Date() 
    };

    setMessages(prev => [...prev, userMsg]);
    const currentInput = input;
    const currentImage = selectedImage;

    setInput('');
    setSelectedImage(null);
    setIsTyping(true);

    try {
      const history = messages.map(m => ({
        role: m.role,
        parts: [{ text: m.text }]
      }));

      const response = await chatWithMediGenie(currentInput || "Analyze input.", currentImage, history, profile);
      const fullText = response.text || "I'm sorry, I couldn't generate a response.";

      let confidence: 'Low' | 'Medium' | 'High' | undefined;
      if (fullText.toLowerCase().includes('confidence: high')) confidence = 'High';
      else if (fullText.toLowerCase().includes('confidence: medium')) confidence = 'Medium';
      else if (fullText.toLowerCase().includes('confidence: low')) confidence = 'Low';

      const botMsg: ChatMessage = {
        role: 'model',
        text: fullText,
        timestamp: new Date(),
        confidence,
        activeAgent: currentImage ? 'Symptom Analyzer' : 'Medical Librarian'
      };
      setMessages(prev => [...prev, botMsg]);
    } catch (error) {
      setMessages(prev => [...prev, {
        role: 'model',
        text: "I encountered an error. Safety Officer intervention required.",
        timestamp: new Date(),
        activeAgent: 'Safety Officer'
      }]);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <div className="flex flex-col h-full max-w-4xl mx-auto border glass rounded-3xl overflow-hidden shadow-xl">
      <div className="bg-slate-900 p-4 text-white flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-blue-600 rounded-full flex items-center justify-center shadow-lg shadow-blue-500/20">
            <ShieldCheck className="w-6 h-6 text-white" />
          </div>
          <div>
            <h3 className="font-bold">MediGenie Orchestrator</h3>
            <div className="flex gap-1.5 mt-0.5">
              {['Safety Officer', 'Symptom Analyzer'].map((a:any) => (
                <span key={a} className="w-1.5 h-1.5 bg-emerald-400 rounded-full animate-pulse"></span>
              ))}
            </div>
          </div>
        </div>
        <div className="hidden sm:flex items-center gap-2 bg-white/10 px-3 py-1.5 rounded-lg text-xs font-medium">
          <Lock size={12} className="text-emerald-400" />
          <span>HIPAA-Style Privacy Shield Active</span>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-6 space-y-6 bg-slate-50/50" ref={scrollRef}>
        {messages.map((m, i) => (
          <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`flex gap-3 max-w-[85%] ${m.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
              <div className={`w-8 h-8 rounded-full flex items-center justify-center shrink-0 ${m.role === 'user' ? 'bg-blue-600' : 'bg-white border shadow-sm'}`}>
                {m.role === 'user' ? <User size={16} className="text-white" /> : <ShieldCheck size={16} className="text-blue-600" />}
              </div>
              <div className="space-y-2">
                {m.activeAgent && <AgentBadge name={m.activeAgent} />}
                <div className={`p-4 rounded-2xl shadow-sm space-y-3 ${
                  m.role === 'user' 
                  ? 'bg-blue-600 text-white rounded-tr-none' 
                  : 'bg-white text-slate-800 rounded-tl-none border border-slate-100'
                }`}>
                  {m.image && (
                    <div className="rounded-xl overflow-hidden mb-2 max-w-[240px]">
                      <img src={m.image} alt="Upload" className="w-full h-auto object-cover" />
                    </div>
                  )}
                  <p className="text-sm leading-relaxed whitespace-pre-wrap">{m.text}</p>
                </div>
                {m.confidence && (
                  <div className={`inline-flex items-center gap-1.5 px-3 py-1 rounded-full text-[10px] font-bold border uppercase tracking-wider bg-white shadow-xs`}>
                    Confidence: {m.confidence}
                  </div>
                )}
              </div>
            </div>
          </div>
        ))}
        {isTyping && (
          <div className="flex justify-start">
            <div className="flex gap-3 items-center">
              <div className="w-8 h-8 rounded-full bg-white border shadow-sm flex items-center justify-center">
                <ShieldCheck size={16} className="text-blue-600" />
              </div>
              <div className="bg-white px-4 py-3 rounded-2xl rounded-tl-none shadow-sm border border-slate-100 flex gap-1">
                <span className="w-1.5 h-1.5 bg-blue-600 rounded-full animate-bounce"></span>
                <span className="w-1.5 h-1.5 bg-blue-600 rounded-full animate-bounce delay-100"></span>
                <span className="w-1.5 h-1.5 bg-blue-600 rounded-full animate-bounce delay-200"></span>
              </div>
            </div>
          </div>
        )}
      </div>

      <div className="p-4 bg-white border-t">
        <div className="flex items-center gap-2 max-w-4xl mx-auto">
          <button
            onClick={() => fileInputRef.current?.click()}
            className="w-10 h-10 bg-slate-50 text-slate-400 hover:bg-slate-100 hover:text-blue-600 rounded-xl flex items-center justify-center transition-all"
          >
            <ImageIcon size={20} />
          </button>
          <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={(e:any) => {
            const file = e.target.files[0];
            const reader = new FileReader();
            reader.onload = () => setSelectedImage(reader.result as string);
            reader.readAsDataURL(file);
          }} />
          <input
            type="text"
            className="flex-1 bg-slate-100 rounded-2xl px-6 py-3 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500/20"
            placeholder="Talk to the orchestrator..."
            value={input}
            onChange={e => setInput(e.target.value)}
            onKeyDown={e => e.key === 'Enter' && handleSend()}
          />
          <button
            onClick={handleSend}
            disabled={isTyping}
            className="w-12 h-12 bg-blue-600 text-white rounded-2xl flex items-center justify-center shadow-lg shadow-blue-200"
          >
            <Send size={20} />
          </button>
        </div>
      </div>
    </div>
  );
};

