            reader.onload = () => setSelectedImage(reader.result as string);
            reader.readAsDataURL(file);
          }} />
          <input
            type="text"
            className="flex-1 bg-slate-100 rounded-2xl px-6 py-3 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500/20"
            placeholder="Describe symptoms or upload a photo..."
            value={input}
            onChange={e => setInput(e.target.value)}
            onKeyDown={e => e.key === 'Enter' && handleSend()}
          />
          <button
            onClick={handleSend}
            disabled={isTyping || (!input.trim() && !selectedImage)}
            className="w-12 h-12 bg-blue-600 text-white rounded-2xl flex items-center justify-center shadow-lg shadow-blue-200 disabled:bg-slate-300"
          >
            <Send size={20} />
