        </div>
        <p className="text-[10px] text-slate-400 text-center mt-2 flex items-center justify-center gap-1">
          <AlertCircle size={10} /> Disclaimer: MediGenie suggestions are not clinical diagnoses.
        </p>
      </div>
    </div>
  );
};

