// 1. Safety & Compliance Agent (Global boundary enforcer)
const SAFETY_INSTRUCTIONS = `
  STRICT SAFETY RULES:
  - NEVER state a definitive diagnosis.
  - ALWAYS include: "This is not medical advice. Consult a doctor."
  - If "Emergency" risk is detected, stop all other logic and insist on calling emergency services.
  - Disclaimer: "MediGenie recommendations are for informational purposes only. Do not exceed specified dosages."
`;

// 2. Prescription & Safety Agent
export const prescriptionSafetyAgent = async (query: string, userProfile: UserProfile) => {
  const systemInstruction = `
    You are the Prescription Safety Agent. 
    Your goal is to recommend a common medicine for the user's symptoms while being extremely cautious.

    CHECKLIST:
    1. Check for allergies in profile: ${userProfile.allergies.join(', ')}.
    2. Check for contraindications: (BP: ${userProfile.medicalHistory.includes('BP') || userProfile.medicalHistory.includes('hypertension')}, Pregnancy: ${userProfile.gender === 'Female' && userProfile.medicalHistory.includes('pregnant')}).
    3. Identify standard OTC medication, adult dosage, side effects, and strict warnings.

    RESPONSE FORMAT (JSON ONLY):
    {
      "medication": "Name",
      "dosage": "Typical amount/frequency",
      "sideEffects": ["effect 1", "effect 2"],
      "warnings": ["warning 1", "warning 2"],
      "reasoning": "Brief clinical explanation"
    }

    ${SAFETY_INSTRUCTIONS}
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: [{ role: 'user', parts: [{ text: `User request: ${query}` }] }],
    config: { systemInstruction, responseMimeType: "application/json" },
  });

  // Use property access for .text as per guidelines
  return JSON.parse(response.text || '{}');
};

// 3. Symptom Analysis Agent (Refined for Images)
export const analyzeSymptomsAgent = async (input: string, imageData?: string) => {
  const systemInstruction = `
    You are the Symptom Analysis Agent. 
    Task: Interpret text or images (rashes, wounds).
    If an image of a rash or wound is provided:
    - Describe the appearance (color, borders, texture).
    - Ask clarifying questions (itching, pain duration).
    - Avoid diagnosis.
    ${SAFETY_INSTRUCTIONS}
  `;
  const parts: any[] = [{ text: input }];
  if (imageData) parts.push({ inlineData: { data: imageData.split(',')[1], mimeType: 'image/jpeg' } });

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: [{ role: 'user', parts }],
    config: { systemInstruction },
  });
  return response.text;
};

