  useEffect(() => {
    localStorage.setItem('medi_logs', JSON.stringify(logs));
  }, [logs]);

  const refreshMemory = async (currentLogs: FollowUpLog[]) => {
    setIsRefreshingMemory(true);
    try {
      const summary = await summarizeHealthMemory(profile, currentLogs);
      setProfile({ ...profile, healthSummary: summary });
    } catch (e) {
      console.error("Memory Agent failed", e);
    } finally {
      setIsRefreshingMemory(false);
    }
  };

  const handleAddLog = async () => {
    if (!newLog.condition || !newLog.notes) return;
    setLoading(true);

    const log: FollowUpLog = {
      id: Date.now().toString(),
      date: new Date(),
      condition: newLog.condition,
      status: newLog.status as any,
      notes: newLog.notes
    };

    try {
      const feedback = await followUpAgent(profile, logs, JSON.stringify(log));
      setAiFeedback(feedback || "Log saved successfully.");
      const updatedLogs = [log, ...logs];
      setLogs(updatedLogs);

      // Refresh AI Long-Term Memory
      await refreshMemory(updatedLogs);

      setNewLog({ condition: '', status: 'Stable', notes: '' });
      setShowAdd(false);
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-5xl mx-auto space-y-8 animate-in fade-in duration-500 pb-12">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-bold text-slate-900 flex items-center gap-2">
            <TrendingUp className="text-blue-600" /> Recovery Tracker
          </h2>
          <p className="text-slate-500">The Follow-up Agent monitors your long-term health narrative.</p>
        </div>
        <button 
          onClick={() => setShowAdd(true)}
          className="bg-blue-600 text-white px-6 py-3 rounded-2xl font-bold flex items-center gap-2 hover:bg-blue-700 transition-all shadow-lg shadow-blue-100"
        >
          <Plus size={20} /> Log Today's Progress
        </button>
      </div>

      {/* Long Term Memory Summary Card */}
      <div className="bg-slate-900 rounded-3xl p-8 text-white relative overflow-hidden shadow-xl border border-white/10">
        <div className="absolute top-0 right-0 p-8 opacity-10">
          <BrainCircuit size={120} />
        </div>
        <div className="relative z-10 flex flex-col md:flex-row md:items-center justify-between gap-6">
          <div className="space-y-3 max-w-2xl">
            <div className="flex items-center gap-2 text-blue-400 font-bold uppercase tracking-widest text-xs">
              <BrainCircuit size={16} /> MediGenie Agentic Memory
            </div>
            <h3 className="text-xl font-bold">Current Health Narrative</h3>
            <p className="text-blue-100/80 text-sm leading-relaxed italic">
              {profile.healthSummary ? `"${profile.healthSummary}"` : "Start logging your symptoms to build a long-term health narrative."}
            </p>
          </div>
          <button 
            onClick={() => refreshMemory(logs)}
            disabled={isRefreshingMemory || logs.length === 0}
            className="flex items-center gap-2 bg-white/10 hover:bg-white/20 px-4 py-2 rounded-xl text-xs font-bold transition-all disabled:opacity-30"
          >
            {isRefreshingMemory ? <Loader2 size={14} className="animate-spin" /> : <RefreshCw size={14} />}
            Sync Memory
          </button>
        </div>
      </div>

      {aiFeedback && (
        <div className="bg-blue-50 border border-blue-200 p-6 rounded-3xl animate-in zoom-in-95 duration-300">
          <div className="flex items-center gap-3 mb-2">
            <Activity className="text-blue-600" size={20} />
            <h4 className="font-bold text-blue-900">Follow-up Agent Feedback</h4>
          </div>
          <p className="text-blue-800 text-sm leading-relaxed italic">"{aiFeedback}"</p>
          <button onClick={() => setAiFeedback(null)} className="text-[10px] text-blue-400 font-bold uppercase mt-4 hover:text-blue-600">Dismiss</button>
        </div>
      )}

      {showAdd && (
        <div className="bg-white p-8 rounded-3xl border shadow-xl animate-in slide-in-from-top-4 duration-300">
          <div className="flex items-center justify-between mb-6">
            <h3 className="text-xl font-bold">Log Health Update</h3>
            <button onClick={() => setShowAdd(false)} className="text-slate-400 hover:text-slate-600"><Calendar size={20}/></button>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="space-y-2">
              <label className="text-xs font-bold text-slate-400 uppercase">Condition Tracked</label>
              <input 
                type="text" 
                className="w-full bg-slate-50 border rounded-xl px-4 py-3 outline-none focus:ring-2 focus:ring-blue-500"
                placeholder="e.g. Lower Back Pain"
                value={newLog.condition}
                onChange={e => setNewLog({...newLog, condition: e.target.value})}
              />
            </div>
            <div className="space-y-2">
              <label className="text-xs font-bold text-slate-400 uppercase">Status</label>
              <select 
                className="w-full bg-slate-50 border rounded-xl px-4 py-3 outline-none"
                value={newLog.status}
                onChange={e => setNewLog({...newLog, status: e.target.value})}
              >
                <option>Improving</option>
                <option>Stable</option>
                <option>Worsening</option>
              </select>
            </div>
            <div className="md:col-span-2 space-y-2">
              <label className="text-xs font-bold text-slate-400 uppercase">Notes & Observations</label>
              <textarea 
                className="w-full bg-slate-50 border rounded-xl p-4 h-32 outline-none focus:ring-2 focus:ring-blue-500"
                placeholder="Describe how you're feeling today compared to yesterday..."
                value={newLog.notes}
                onChange={e => setNewLog({...newLog, notes: e.target.value})}
              />
            </div>
          </div>
          <button 
            onClick={handleAddLog}
            disabled={loading || !newLog.condition}
            className="w-full bg-blue-600 text-white py-4 rounded-2xl font-bold mt-6 hover:bg-blue-700 disabled:opacity-50 transition-all flex items-center justify-center gap-2"
          >
            {loading ? <Loader2 className="animate-spin" /> : <CheckCircle2 size={20}/>}
            Save & Analyze Progress
          </button>
        </div>
      )}

      <div className="grid grid-cols-1 gap-4">
        {logs.length === 0 ? (
          <div className="bg-white p-20 rounded-3xl border border-dashed border-slate-200 text-center space-y-4">
            <TrendingUp className="mx-auto text-slate-200" size={48} />
            <p className="text-slate-400 font-medium">No progress logs found. Start tracking to see recovery trends.</p>
          </div>
        ) : (
          logs.map((log) => (
            <div key={log.id} className="bg-white p-6 rounded-3xl border border-slate-100 shadow-sm hover:shadow-md transition-shadow group">
              <div className="flex items-start justify-between">
                <div className="flex items-center gap-4">
                  <div className={`w-12 h-12 rounded-2xl flex items-center justify-center ${
                    log.status === 'Improving' ? 'bg-emerald-100 text-emerald-600' : 
                    log.status === 'Worsening' ? 'bg-rose-100 text-rose-600' : 'bg-blue-100 text-blue-600'
                  }`}>
                    {log.status === 'Improving' ? <TrendingUp size={24}/> : 
                     log.status === 'Worsening' ? <AlertCircle size={24}/> : <Activity size={24}/>}
                  </div>
                  <div>
                    <h4 className="font-bold text-slate-900">{log.condition}</h4>
                    <p className="text-xs text-slate-400">{log.date.toLocaleDateString()} at {log.date.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</p>
                  </div>
                </div>
                <span className={`px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider ${
                  log.status === 'Improving' ? 'bg-emerald-50 text-emerald-600' : 
                  log.status === 'Worsening' ? 'bg-rose-50 text-rose-600' : 'bg-blue-50 text-blue-600'
                }`}>
                  {log.status}
                </span>
              </div>
              <p className="mt-4 text-sm text-slate-600 leading-relaxed pl-16">{log.notes}</p>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

