`;

// 1. Memory Agent: Synthesizes logs into a long-term health summary
export const summarizeHealthMemory = async (profile: UserProfile, logs: FollowUpLog[]) => {
  const systemInstruction = `
    You are the Memory Agent. 
    Your task is to review the user's clinical profile and recent progress logs to create a 2-3 sentence "Health Narrative".
    This narrative should capture ongoing issues, current medications, and significant changes.
    Focus on continuity of care.
  `;

  const prompt = `
    User Profile: ${profile.name}, Age ${profile.age}, Allergies: ${profile.allergies.join(', ')}.
    History: ${profile.medicalHistory}.
    Recent Logs: ${JSON.stringify(logs.slice(0, 5))}.

    Synthesize this into a concise Health Narrative for future medical reference.
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: [{ role: 'user', parts: [{ text: prompt }] }],
    config: { systemInstruction },
  });

  return response.text;
};

// 2. Enhanced Follow-up Agent: Uses long-term memory for check-ins
export const followUpAgent = async (profile: UserProfile, previousLogs: FollowUpLog[], currentUpdate: string) => {
  const systemInstruction = `
    You are the Follow-up Coordinator.
    Task: Review the user's current update against their Long-Term Health Summary.
    Health Summary: ${profile.healthSummary || 'None available yet.'}

    If the user reports a recurring issue (e.g. chest pain mentioned last week), acknowledge the history.
    Provide empathetic, clinical-style feedback.
    ${SAFETY_INSTRUCTIONS}
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: [{ role: 'user', parts: [{ text: `Current Status: ${currentUpdate}. Previous Logs Context: ${JSON.stringify(previousLogs.slice(0, 3))}` }] }],
    config: { systemInstruction },
  });

  return response.text;
};

// 3. Prescription & Safety Agent (Context-Aware)
export const prescriptionSafetyAgent = async (query: string, userProfile: UserProfile) => {
  const systemInstruction = `
    You are the Prescription Safety Agent. 
    Health Summary Context: ${userProfile.healthSummary || 'No recent history.'}

    Recommend a safe medicine while checking against:
    1. Allergies: ${userProfile.allergies.join(', ')}.
    2. Long-term history: ${userProfile.medicalHistory}.

    RESPONSE FORMAT (JSON ONLY):
    {
      "medication": "Name",
      "dosage": "Typical amount/frequency",
      "sideEffects": ["effect 1", "effect 2"],
      "warnings": ["warning 1", "warning 2"],
      "reasoning": "Brief clinical explanation"
    }

    ${SAFETY_INSTRUCTIONS}
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: [{ role: 'user', parts: [{ text: `User request: ${query}` }] }],
    config: { systemInstruction, responseMimeType: "application/json" },
  });

  return JSON.parse(response.text || '{}');
};

