import React, { useState, useEffect } from 'react';
import { UserProfile, DigitalTwin } from '../types';
import { 
  LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, 
  AreaChart, Area 
} from 'recharts';
import { 
  Dna, Cpu, Activity, Zap, Play, Loader2, BrainCircuit, 
  TrendingUp, TrendingDown, Info, ShieldCheck, Microscope
} from 'lucide-react';
import { simulateCounterfactualAgent, updateDigitalTwinAgent } from '../geminiService';

const PatientTwin: React.FC<{ profile: UserProfile, setProfile: (p: UserProfile) => void }> = ({ profile, setProfile }) => {
  const [simulationQuery, setSimulationQuery] = useState('');
  const [simulationResult, setSimulationResult] = useState<string | null>(null);
  const [isSimulating, setIsSimulating] = useState(false);
  const [isUpdating, setIsUpdating] = useState(false);

  // Use the twin from profile or default data
  const twin = profile.digitalTwin;

  const handleUpdateTwin = async () => {
    setIsUpdating(true);
    try {
      const logs = JSON.parse(localStorage.getItem('medi_logs') || '[]');
      const newTwin = await updateDigitalTwinAgent(profile, logs);
      setProfile({ ...profile, digitalTwin: newTwin });
    } catch (e) {
      console.error("Twin update failed", e);
    } finally {
      setIsUpdating(false);
    }
  };

  const handleSimulate = async () => {
    if (!simulationQuery.trim() || !twin) return;
    setIsSimulating(true);
    try {
      const result = await simulateCounterfactualAgent(twin, profile, simulationQuery);
      setSimulationResult(result);
    } catch (e) {
      console.error("Simulation failed", e);
    } finally {
      setIsSimulating(false);
    }
  };

  return (
    <div className="max-w-7xl mx-auto space-y-8 pb-12 animate-in fade-in duration-700">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h2 className="text-4xl font-black text-slate-900 flex items-center gap-3 italic tracking-tighter">
            <Cpu className="text-blue-600 animate-pulse" /> PATIENT DIGITAL TWIN
          </h2>
          <p className="text-slate-500 font-medium">Longitudinal Health Modeling & Counterfactual Simulation</p>
        </div>
        <button 
          onClick={handleUpdateTwin}
          disabled={isUpdating}
          className="bg-slate-900 text-white px-6 py-3 rounded-2xl font-bold flex items-center gap-2 hover:bg-blue-600 transition-all shadow-xl disabled:opacity-50 group"
        >
          {isUpdating ? <Loader2 size={20} className="animate-spin" /> : <Microscope size={20} className="group-hover:rotate-12 transition-transform" />}
          Reconstruct Health Model
        </button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* Left Column: Visual Twin Stats */}
        <div className="lg:col-span-8 space-y-8">
          {!twin ? (
            <div className="bg-white border-2 border-dashed border-slate-200 rounded-[3rem] p-20 text-center space-y-4">
              <Dna size={64} className="mx-auto text-slate-200 animate-bounce" />
              <h3 className="text-xl font-bold text-slate-400 tracking-tight">No Active Model Detected</h3>
              <p className="text-slate-400 max-w-sm mx-auto text-sm">Synchronize your logs to construct an evolving computational model of your health status.</p>
            </div>
          ) : (
            <>
              {/* Equilibrium Status */}
              <div className="bg-slate-900 rounded-[2.5rem] p-10 text-white relative overflow-hidden shadow-2xl border border-white/5">
                <div className="absolute top-0 right-0 p-12 opacity-5 scale-150 rotate-12">
                  <BrainCircuit size={200} />
                </div>
                <div className="relative z-10 space-y-6">
                  <div className="flex items-center gap-2 bg-blue-500/20 text-blue-400 px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-[0.2em] w-fit">
                    <Activity size={12} /> Model Equilibrium
                  </div>
                  <h3 className="text-3xl font-black tracking-tight leading-none italic uppercase">Systemic State Summary</h3>
                  <p className="text-xl text-blue-100/90 font-medium leading-relaxed max-w-3xl">
                    "{twin.equilibriumStatus}"
                  </p>
                  <div className="flex items-center gap-6 pt-4 border-t border-white/10">
                    <div className="flex items-center gap-2 text-emerald-400 font-bold">
                      <Zap size={16} /> Metabolic Stability: High
                    </div>
                    <div className="flex items-center gap-2 text-blue-300 font-bold">
                      <ShieldCheck size={16} /> Homeostasis: Stable
                    </div>
                  </div>
                </div>
              </div>

              {/* Trajectories Grid */}
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                {twin.trajectories.map((t, i) => (
                  <div key={i} className="bg-white p-8 rounded-[2rem] border border-slate-100 shadow-sm space-y-6">
                    <div className="flex items-center justify-between">
                      <h4 className="font-black text-slate-900 uppercase tracking-tighter italic text-lg">{t.label} Trajectory</h4>
                      <div className="flex items-center gap-1 text-[10px] font-bold text-emerald-600 bg-emerald-50 px-2 py-0.5 rounded-full uppercase">
                        <TrendingUp size={10} /> 4.2% Growth
                      </div>
                    </div>
                    <div className="h-[180px] w-full">
                      <ResponsiveContainer width="100%" height="100%">
                        <AreaChart data={t.values.map((v, idx) => ({ value: v, date: t.dates[idx] }))}>
                          <defs>
                            <linearGradient id={`grad-${i}`} x1="0" y1="0" x2="0" y2="1">
                              <stop offset="5%" stopColor="#3b82f6" stopOpacity={0.2}/>
                              <stop offset="95%" stopColor="#3b82f6" stopOpacity={0}/>
                            </linearGradient>
                          </defs>
                          <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                          <Tooltip contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)' }} />
                          <Area type="monotone" dataKey="value" stroke="#3b82f6" strokeWidth={4} fill={`url(#grad-${i})`} />
                        </AreaChart>
                      </ResponsiveContainer>
                    </div>
                  </div>
                ))}
              </div>
            </>
          )}
        </div>

        {/* Right Column: Counterfactual Simulator */}
        <div className="lg:col-span-4 space-y-8">
          <div className="bg-indigo-600 rounded-[2.5rem] p-8 text-white shadow-2xl relative overflow-hidden group">
            <div className="absolute top-0 right-0 p-8 opacity-10 group-hover:scale-110 transition-transform">
              <Zap size={100} />
            </div>
            <h3 className="text-2xl font-black italic tracking-tighter uppercase mb-6">What-If Simulation</h3>
            <p className="text-indigo-100/80 text-sm mb-6 leading-relaxed font-medium">
              Run counterfactual scenarios on your digital twin to predict outcome shifts based on lifestyle alterations.
            </p>

            <div className="space-y-4">
              <textarea 
                className="w-full bg-indigo-700/50 border border-white/20 rounded-[1.5rem] p-5 text-sm outline-none focus:ring-2 focus:ring-white/50 placeholder:text-white/30 font-medium h-32 resize-none"
                placeholder="e.g. Predict the impact of 200mg daily caffeine reduction on my resting heart rate trend."
                value={simulationQuery}
                onChange={(e) => setSimulationQuery(e.target.value)}
              />
              <button 
                onClick={handleSimulate}
                disabled={isSimulating || !twin}
                className="w-full bg-white text-indigo-600 py-4 rounded-2xl font-black italic uppercase tracking-wider hover:bg-indigo-50 transition-all flex items-center justify-center gap-2 shadow-lg disabled:opacity-50"
              >
                {isSimulating ? <Loader2 className="animate-spin" /> : <Play size={18} fill="currentColor" />}
                Run Health Simulation
              </button>
            </div>

            {simulationResult && (
              <div className="mt-8 bg-white/10 border border-white/10 p-6 rounded-[2rem] animate-in zoom-in-95 duration-500">
                <div className="flex items-center gap-2 text-[10px] font-black uppercase tracking-widest text-indigo-200 mb-3">
                  <Cpu size={12} /> Simulation Output
                </div>
                <p className="text-sm leading-relaxed text-white/90 font-medium italic">
                  "{simulationResult}"
                </p>
                <button 
                  onClick={() => setSimulationResult(null)}
                  className="mt-4 text-[10px] font-black uppercase tracking-widest text-indigo-300 hover:text-white transition-colors"
                >
                  Clear Projection
                </button>
              </div>
            )}
          </div>

          {/* Med Response Model */}
          <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm space-y-6">
            <h4 className="text-lg font-black italic tracking-tighter uppercase flex items-center gap-2">
              <Dna className="text-blue-600" size={20} /> Pharmacological Response
            </h4>
            <div className="space-y-4">
              {twin?.medicationResponses.map((m, i) => (
                <div key={i} className="bg-slate-50 p-5 rounded-2xl border border-slate-100 space-y-3">
                  <div className="flex items-center justify-between">
                    <span className="font-bold text-slate-900">{m.med}</span>
                    <span className={`px-2 py-0.5 rounded-full text-[9px] font-black uppercase tracking-widest ${
                      m.effectiveness === 'High' ? 'bg-emerald-100 text-emerald-600' : 'bg-amber-100 text-amber-600'
                    }`}>
                      {m.effectiveness} Efficacy
                    </span>
                  </div>
                  <div className="flex items-center gap-2 text-[10px] font-bold text-slate-400">
                    <Info size={12} /> Side Effects: <span className="text-slate-600">{m.sideEffectsSeverity}</span>
                  </div>
                </div>
              )) || (
                <p className="text-xs text-slate-400 italic text-center py-6">Insufficient data for pharm-model construction.</p>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default PatientTwin;

import React, { useState, useEffect } from 'react';
