            <RefreshCcw size={14} />
            <span className="hidden sm:inline">New Chat</span>
          </button>
          <div className="hidden sm:flex items-center gap-2 bg-white/10 px-3 py-1.5 rounded-lg text-xs font-medium border border-white/5">
            <Lock size={12} className="text-emerald-400" />
            <span>Privacy Shield Active</span>
          </div>
        </div>
