const Chat: React.FC<{ profile: UserProfile }> = ({ profile }) => {
  const getInitialMessage = (): ChatMessage => ({
    role: 'model',
    text: `Greetings ${profile.name}. MediGenie Agentic Cluster is active. I have synced your Patient Digital Twin and am ready for multi-agent health analysis. How may I assist your medical journey today?`,
    timestamp: new Date(),
    activeAgent: 'Safety Officer'
  });

  const [messages, setMessages] = useState<ChatMessage[]>([getInitialMessage()]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [currentThinkingAgent, setCurrentThinkingAgent] = useState<string>('Orchestrator');
  const [selectedImage, setSelectedImage] = useState<string | null>(null);
  const scrollRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isTyping]);

  // Simulate agentic handoffs during thinking state
  useEffect(() => {
    if (isTyping) {
      const agents = ['Orchestrator', 'Symptom Analyzer', 'Medical Librarian', 'Safety Officer'];
      let i = 0;
      const interval = setInterval(() => {
        setCurrentThinkingAgent(agents[i % agents.length]);
        i++;
      }, 1500);
      return () => clearInterval(interval);
    }
  }, [isTyping]);

  const handleNewChat = () => {
    if (window.confirm("Terminate current session and clear health context?")) {
      setMessages([getInitialMessage()]);
      setInput('');
      setSelectedImage(null);
    }
  };

  const handleSend = async () => {
    if ((!input.trim() && !selectedImage) || isTyping) return;

    const userMsg: ChatMessage = { 
      role: 'user', 
      text: input || (selectedImage ? "Visual Symptom Analysis Request." : ""), 
      image: selectedImage || undefined,
      timestamp: new Date() 
    };

    setMessages(prev => [...prev, userMsg]);
    const currentInput = input;
    const currentImage = selectedImage;

    setInput('');
    setSelectedImage(null);
    setIsTyping(true);

    try {
      const history = messages.map(m => ({
        role: m.role,
        parts: [{ text: m.text }]
      }));

      const response = await chatWithMediGenie(currentInput || "Analyze clinical context.", currentImage, history, profile);
      const fullText = response.text || "Communication timeout with clinical agents.";
      const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];

      let recommendation = undefined;
      let activeAgent: AgentName = 'Medical Librarian';

      if (currentImage) activeAgent = 'Symptom Analyzer';
      else if (currentInput.toLowerCase().match(/med|pill|tablet|dose|interaction/)) activeAgent = 'Prescription Safety Agent';
      else if (currentInput.toLowerCase().match(/simulate|predict|if I/)) activeAgent = 'Counterfactual Simulator';
      else if (currentInput.toLowerCase().match(/history|last time|previously/)) activeAgent = 'Memory Agent';

      if (activeAgent === 'Prescription Safety Agent' || currentInput.toLowerCase().match(/pain|fever|cough/)) {
        try {
          recommendation = await prescriptionSafetyAgent(currentInput, profile);
        } catch (e) { console.error(e); }
      }

      const botMsg: ChatMessage = {
        role: 'model',
        text: fullText,
        timestamp: new Date(),
        activeAgent: activeAgent,
        recommendation: recommendation && recommendation.medication ? recommendation : undefined,
        sources: sources.map((s: any) => ({ title: s.web?.title || 'Clinical Reference', uri: s.web?.uri || '#' }))
      };
      setMessages(prev => [...prev, botMsg]);
    } catch (error) {
      setMessages(prev => [...prev, {
        role: 'model',
        text: "Safety protocol triggered. Connection to clinical cluster lost.",
        timestamp: new Date(),
        activeAgent: 'Safety Officer'
      }]);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <div className="flex flex-col h-full max-w-5xl mx-auto border glass rounded-[2.5rem] overflow-hidden shadow-2xl animate-in fade-in duration-700">
      {/* Dynamic Header */}
      <div className="bg-slate-900 p-6 text-white flex items-center justify-between">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 bg-blue-600 rounded-2xl flex items-center justify-center shadow-lg shadow-blue-500/20 rotate-3 border border-white/10">
            <ShieldCheck className="w-7 h-7 text-white" />
          </div>
          <div>
            <h3 className="font-black italic uppercase tracking-tighter text-xl leading-none">MediGenie Clinical Cluster</h3>
            <div className="flex items-center gap-3 mt-1.5">
              <div className="flex gap-1.5">
                {[1, 2, 3].map((a) => (
                  <span key={a} className="w-1.5 h-1.5 bg-emerald-400 rounded-full animate-pulse"></span>
                ))}
              </div>
              <span className="text-[10px] font-black uppercase tracking-[0.25em] text-slate-400 italic">Agentic Multi-Modal Intelligence</span>
            </div>
          </div>
        </div>
        <div className="flex items-center gap-3">
          <button 
            onClick={handleNewChat}
            className="flex items-center gap-2 bg-white/5 hover:bg-white/10 px-5 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all border border-white/10 group active:scale-95"
          >
            <RefreshCcw size={14} className="group-hover:rotate-180 transition-transform duration-700" />
            Clear Context
          </button>
          <div className="hidden sm:flex items-center gap-2 bg-emerald-500/10 px-5 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest border border-emerald-500/20 text-emerald-400 italic">
            <Lock size={12} /> Encrypted
          </div>
        </div>
      </div>

      {/* Message Feed */}
      <div className="flex-1 overflow-y-auto p-8 space-y-10 bg-slate-50/20" ref={scrollRef}>
        {messages.map((m, i) => (
          <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`flex gap-5 max-w-[90%] ${m.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
              <div className={`w-12 h-12 rounded-2xl flex items-center justify-center shrink-0 shadow-lg border ${
                m.role === 'user' ? 'bg-slate-900 text-white border-white/10' : 'bg-white text-blue-600 border-slate-100'
              }`}>
                {m.role === 'user' ? <User size={24} /> : <ShieldCheck size={24} />}
              </div>
              <div className="flex flex-col">
                {m.activeAgent && <AgentBadge name={m.activeAgent} />}
                <div className={`p-6 rounded-[2rem] shadow-sm space-y-4 relative overflow-hidden ${
                  m.role === 'user' 
                  ? 'bg-slate-900 text-white rounded-tr-none' 
                  : 'bg-white text-slate-800 rounded-tl-none border border-slate-100'
                }`}>
                  {m.image && (
                    <div className="rounded-2xl overflow-hidden mb-4 border border-white/5 shadow-2xl">
                      <img src={m.image} alt="Clinical Sample" className="w-full h-auto object-cover max-h-[400px]" />
                    </div>
                  )}
                  <p className="text-base leading-relaxed whitespace-pre-wrap font-medium">{m.text}</p>

                  {m.recommendation && <PrescriptionCard rec={m.recommendation} />}

                  {/* Grounded Sources */}
                  {m.sources && m.sources.length > 0 && (
                    <div className="pt-4 mt-4 border-t border-slate-50 space-y-3">
