                  <span className={`absolute bottom-3 text-[9px] font-black opacity-20 uppercase tracking-[0.2em] italic ${m.role === 'user' ? 'right-6 text-white' : 'left-6 text-slate-400'}`}>
                    LOG_ID_{m.timestamp.getTime().toString(16).toUpperCase()}
                  </span>
                </div>
              </div>
            </div>
          </div>
