                  <span className="w-2 h-2 bg-blue-600 rounded-full animate-bounce delay-150"></span>
                  <span className="w-2 h-2 bg-blue-600 rounded-full animate-bounce delay-300"></span>
                </div>
                <div className="flex flex-col">
                  <span className="text-[10px] font-black uppercase tracking-[0.25em] text-blue-600 italic">Clinical Routing</span>
                  <span className="text-xs font-bold text-slate-400 italic">Agentic {currentThinkingAgent} processing evidence...</span>
                </div>
              </div>
            </div>
          </div>
        )}
      </div>

      {/* Input Area */}
      <div className="p-8 bg-white border-t border-slate-100">
        {selectedImage && (
          <div className="mb-6 flex items-center gap-5 bg-blue-600/5 p-4 rounded-[2rem] border-2 border-dashed border-blue-200 animate-in slide-in-from-bottom-4 duration-500">
            <div className="w-24 h-24 rounded-2xl overflow-hidden relative shadow-2xl border-2 border-white">
              <img src={selectedImage} alt="Preview" className="w-full h-full object-cover" />
              <button 
                onClick={() => setSelectedImage(null)}
                className="absolute top-1.5 right-1.5 bg-rose-500 text-white rounded-lg p-1.5 hover:bg-rose-600 transition-all shadow-xl active:scale-90"
              >
                <X size={14} />
              </button>
            </div>
            <div className="space-y-1.5">
              <div className="flex items-center gap-2 text-[10px] font-black uppercase tracking-widest text-blue-600 italic">
                <ImageIcon size={14} /> Multimodal Buffer Loaded
              </div>
              <p className="text-sm text-slate-600 font-bold italic">Image pending routing to Symptom Analyzer...</p>
            </div>
          </div>
