              <div className="bg-white px-6 py-5 rounded-[2rem] rounded-tl-none shadow-sm border border-slate-100 flex items-center gap-3">
                <div className="flex gap-1.5">
                  <span className="w-2 h-2 bg-blue-600 rounded-full animate-bounce"></span>
                  <span className="w-2 h-2 bg-blue-600 rounded-full animate-bounce delay-150"></span>
                  <span className="w-2 h-2 bg-blue-600 rounded-full animate-bounce delay-300"></span>
                </div>
                <div className="flex flex-col">
                  <span className="text-[10px] font-black uppercase tracking-[0.25em] text-blue-600 italic">Processing Data</span>
                  <span className="text-xs font-bold text-slate-400 italic">Agent: {currentThinkingAgent}</span>
                </div>
              </div>
            </div>
          </div>
        )}
      </div>

      <div className="p-8 bg-white border-t border-slate-100">
        <div className="flex items-center gap-4 max-w-5xl mx-auto">
          <button
            onClick={() => fileInputRef.current?.click()}
            className="w-14 h-14 bg-slate-100 text-slate-500 hover:bg-blue-600 hover:text-white rounded-2xl flex items-center justify-center transition-all group shadow-inner"
          >
            <ImageIcon size={26} />
          </button>
          <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={(e:any) => {
            const file = e.target.files[0];
            if (!file) return;
            const reader = new FileReader();
            reader.onload = () => setSelectedImage(reader.result as string);
            reader.readAsDataURL(file);
          }} />
          <div className="flex-1 relative">
            <input
              type="text"
              className="w-full bg-slate-100 rounded-[2rem] px-8 py-5 text-base font-bold focus:outline-none focus:ring-4 focus:ring-blue-500/10 placeholder:text-slate-400 transition-all border-none italic"
              placeholder="How do I treat a fever? What is the cost of Ibuprofen?"
              value={input}
              onChange={e => setInput(e.target.value)}
              onKeyDown={e => e.key === 'Enter' && handleSend()}
            />
          </div>
          <button
            onClick={handleSend}
            disabled={isTyping || (!input.trim() && !selectedImage)}
            className="w-16 h-16 bg-blue-600 text-white rounded-[1.5rem] flex items-center justify-center shadow-lg hover:scale-105 active:scale-95 transition-all disabled:opacity-30"
          >
            <Send size={28} />
          </button>
        </div>
      </div>
    </div>
  );
};

