  image?: string;
  timestamp: Date;
  sources?: Array<{ title: string; uri: string }>;
  confidence?: 'Low' | 'Medium' | 'High';
  activeAgent?: AgentName;
  recommendation?: {
    medication: string;
    dosage: string;
    price?: string;
    sideEffects: string[];
    warnings: string[];
  };
}

